#include <iostream>

long long factorial(int n) {
    long long result = 1;
    for (int i = 1; i <= n; i++) {
        result *= i;
    }
    return result;
}

int main() {
    int n, m;
    std::cin >> n >> m;
    long long result = factorial(n) / (factorial(m) * factorial(n - m));
    std::cout << result << std::endl;
    return 0;
}
